sql:
SELECT date, daylight_duration
FROM sunrise_sunset_data
WHERE accuracy > 0.95;

SELECT COUNT(*) AS record_count
FROM sunrise_sunset_data
WHERE location_id = 0;

SELECT MAX(updated_at) AS most_recent_update
FROM sunrise_sunset_data
WHERE location_id = 1;

SELECT AVG(accuracy) AS average_accuracy
FROM sunrise_sunset_data
WHERE date LIKE '2023-05-%';

external_knowledge:
- "the sun shines bright" refers to locations with high daylight hours; 
- "reliable" refers to an accuracy greater than 0.95; 
- "accessible to the assigned users" means the user role has permission to view the data.
